```mlir
firrtl.circuit "Test" {
  firrtl.module @Test() {
    %mid_ref = firrtl.instance child @Mid(in in: !firrtl.ref<uint<1>>)
    %send_ref = firrtl.instance send @send(out dest: !firrtl.ref<uint<1>>) 
    firrtl.strictconnect %mid_ref, %send_ref : !firrtl.ref<uint<1>>
  }
  firrtl.module private @Mid(in %in: !firrtl.ref<uint<1>>) {
    %child_ref = firrtl.instance child @Child(in in: !firrtl.ref<uint<1>>)
    firrtl.strictconnect %child_ref, %in: !firrtl.ref<uint<1>>

     firrtl.instance Test @HasSendSource()
  }
  firrtl.module private @Child(in %in: !firrtl.ref<uint<1>>) {
    %x = firrtl.ref.resolve %in: !firrtl.ref<uint<1>>
    %sink = firrtl.instance sink @Sink(in sink: !firrtl.uint<1>)
    firrtl.strictconnect %sink, %x: !firrtl.uint<1>
  }
  firrtl.extmodule @Sink(in sink: !firrtl.uint<1>)
  firrtl.extmodule @Source(out source: !firrtl.uint<1>)
  firrtl.extmodule @AltSource(out source: !firrtl.uint<4>)

  firrtl.module private @send(out %dest: !firrtl.ref<uint<1>>) {
    // ref.send of an instance result is bugged, bounce through a wire named 'source'
    %source_wire = firrtl.instance srcinst @Source(out source: !firrtl.uint<1>) 
    %source = firrtl.wire : !firrtl.uint<1>
    firrtl.strictconnect %source, %source_wire : !firrtl.uint<1>
    %ref_source = firrtl.ref.send %source : !firrtl.uint<1>
    firrtl.connect %dest, %ref_source : !firrtl.ref<uint<1>>, !firrtl.ref<uint<1>>
  }

  firrtl.module @HasSendSource() {
    %source = firrtl.instance send @AltSource(out source: !firrtl.uint<4> [{class = "firrtl.transforms.DontTouchAnnotation"}])
  }
}
